example_bad:
use std::thread;

fn main() {
    let name = String::from("Rust");
    thread::spawn(|| {
        println!("Hello, {}!", name); // Error: closure may outlive function
    });
}

fixes.code:
use std::thread;

let name = String::from("Rust");
thread::spawn(move || {
    println!("Hello, {}!", name); // Works!
});

use std::thread;

let name = String::from("Rust");
let name_clone = name.clone();
thread::spawn(move || {
    println!("Hello, {}!", name_clone);
});
println!("Still have: {}", name);
